<?php require_once __DIR__.'/../app/bootstrap.php'; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf(); if(isset($_POST['ids'])){ $pdo=db(); $pdo->beginTransaction(); try{ foreach((array)$_POST['ids'] as $id){ $pdo->prepare('DELETE FROM post_items WHERE article_id=?')->execute([$id]); $pdo->prepare('DELETE FROM articles WHERE id=?')->execute([$id]); } $pdo->commit(); }catch(Throwable $e){$pdo->rollBack(); log_event('error','記事削除失敗',$e->getMessage());} }} admin_header('記事一覧'); echo'<form><h3 class=section-title>記事を検索</h3><div class=toolbar><label>キーワード<input name=q placeholder=タイトル・キーワード検索 value="'.e($_GET['q']??'').'"></label><label>並び替え<select name=sort><option value=new>新着順</option><option value=old '.(($_GET['sort']??'')==='old'?'selected':'').'>古い順</option></select></label><button>検索</button></div></form><form method=post><input type=hidden name=csrf value='.csrf_token().'><div class=actions><h3 class=section-title style="margin-right:auto">記事一覧</h3><button class=danger>選択した記事を一括削除</button></div>'; $q='%'.($_GET['q']??'').'%'; $order=($_GET['sort']??'')==='old'?'ASC':'DESC'; $page=max(1,(int)($_GET['page']??1)); $st=db()->prepare("SELECT * FROM articles WHERE title LIKE ? ORDER BY COALESCE(published_at,fetched_at) $order LIMIT 40 OFFSET ".(($page-1)*40)); $st->execute([$q]); echo'<div class=grid>'; $count=0; foreach($st as $a){$count++; echo'<div><a class=article href="'.e($a['url']).'" target=_blank rel=noopener>'.($a['image_url']?'<img src="'.e($a['image_url']).'" alt="">':'<div class=article-placeholder></div>').'<b>'.e($a['title']).'</b></a><label class=article-select><input type=checkbox name="ids[]" value='.$a['id'].'>削除対象</label></div>'; } echo'</div>'; if($count===0) echo'<div class=empty-state>条件に一致する記事はありません。検索条件を変更して再度お試しください。</div>'; echo'</form>'; admin_footer();
